+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5667,6 +5667,56 @@ Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
   // cannot be decomposed into `(icmp samesign ult X, -46) or (icmp samesign ult
   // -46, -32)`. `X` is allowed to be non-negative here.
   Pred = Pred.dropSameSign();
+
+  // Fold: icmp eq/ne (min (max Z, C1), C2), Z
+  //  -> icmp ule/ugt (Z - C1), (C2 - C1)  if C1 <= C2
+  //  -> false/true                         if C1 > C2
+  // Also handle max(min(Z, C1), C2) commutative form.
+  if (CmpInst::isEquality(Pred)) {
+    if (auto *InnerMM = dyn_cast<MinMaxIntrinsic>(X)) {
+      if (InnerMM->getLHS() == Z && InnerMM->isSigned() == MinMax->isSigned()) {
+        // Check that inner is the opposite type (max inside min, or min inside max)
+        bool InnerIsMax = InnerMM->getPredicate() == ICmpInst::ICMP_SGT ||
+                          InnerMM->getPredicate() == ICmpInst::ICMP_UGT;
+        bool OuterIsMax = MinMax->getPredicate() == ICmpInst::ICMP_SGT ||
+                          MinMax->getPredicate() == ICmpInst::ICMP_UGT;
+        if (InnerIsMax != OuterIsMax) {
+          const APInt *C1, *C2;
+          if (match(InnerMM->getRHS(), m_APInt(C1)) &&
+              match(Y, m_APInt(C2))) {
+            // X must have one use (the outer minmax) to avoid increasing
+            // instruction count.
+            if (X->hasOneUse()) {
+              Value *Low = ConstantInt::get(Z->getType(), *C1);
+              Value *High = ConstantInt::get(Z->getType(), *C2);
+              bool ValidRange;
+              if (MinMax->isSigned())
+                ValidRange = C1->sle(*C2);
+              else
+                ValidRange = C1->ule(*C2);
+
+              if (ValidRange) {
+                // (Z - C1) <=u (C2 - C1) for eq, >u for ne
+                Value *Sub = Builder.CreateSub(Z, Low);
+                APInt RangeWidth = *C2 - *C1;
+                Value *Range = ConstantInt::get(Z->getType(), RangeWidth);
+                return new ICmpInst(
+                    Pred == ICmpInst::ICMP_EQ ? ICmpInst::ICMP_ULE
+                                              : ICmpInst::ICMP_UGT,
+                    Sub, Range);
+              } else {
+                // Range is empty
+                return replaceInstUsesWith(
+                    I, ConstantInt::getBool(I.getType(),
+                                            Pred == ICmpInst::ICMP_NE));
+              }
+            }
+          }
+        }
+      }
+    }
+  }
+
   auto CmpXZ = IsCondKnownTrue(simplifyICmpInst(Pred, X, Z, Q));
   auto CmpYZ = IsCondKnownTrue(simplifyICmpInst(Pred, Y, Z, Q));
   if (!CmpXZ.has_value() && !CmpYZ.has_value())
@@ -5709,6 +5759,31 @@ Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
         break;
       MinMaxCmpXZ = IsCondKnownTrue(simplifyICmpInst(NewPred, X, Z, Q));
     }
+    if (!MinMaxCmpXZ.has_value())
+      break;
+    //     Expr       Result
+    // min(X, Y) == Z X <= Y
+    // max(X, Y) == Z X >= Y
+    // min(X, Y) != Z X > Y
+    // max(X, Y) != Z X < Y
+    if ((Pred == ICmpInst::ICMP_EQ) == *CmpXZ) {
+      ICmpInst::Predicate NewPred =
+          ICmpInst::getNonStrictPredicate(MinMax->getPredicate());
+      if (Pred == ICmpInst::ICMP_NE)
+        NewPred = ICmpInst::getInversePredicate(NewPred);
+      return ICmpInst::Create(Instruction::ICmp, NewPred, X, Y);
+    }
+    // Otherwise (X != Z):
+    ICmpInst::Predicate NewPred = MinMax->getPredicate();
+    auto MinMaxCmpXZ = IsCondKnownTrue(simplifyICmpInst(NewPred, X, Z, Q));
+    if (!MinMaxCmpXZ.has_value()) {
+      std::swap(X, Y);
+      std::swap(CmpXZ, CmpYZ);
+      // Re-check pre-condition X != Z
+      if (!CmpXZ.has_value() || (Pred == ICmpInst::ICMP_EQ) == *CmpXZ)
+        break;
+      MinMaxCmpXZ = IsCondKnownTrue(simplifyICmpInst(NewPred, X, Z, Q));
+    }
     if (!MinMaxCmpXZ.has_value())
       break;
     if (*MinMaxCmpXZ) {
@@ -6202,11 +6277,33 @@ Instruction *InstCombinerImpl::foldICmpEquality(ICmpInst &I) {
                                   : ConstantInt::getNullValue(A->getType()));
   }

+
+  // icmp eq/ne X, (smin (smax X, Low), High) -> (X - Low) ult/uge (High - Low + 1)
+  // This checks if X is in the signed range [Low, High].
+  const APInt *Low, *High;
+  Value *X;
+  if (match(&I, m_c_ICmp(m_Value(X),
+                          m_OneUse(m_Intrinsic<Intrinsic::smin>(
+                              m_OneUse(m_Intrinsic<Intrinsic::smax>(
+                                  m_Deferred(X), m_APInt(Low))),
+                              m_APInt(High)))))) {
+    if (High->sge(*Low)) {
+      APInt Diff = *High - *Low + 1;
+      Value *Sub = Builder.CreateSub(X, ConstantInt::get(X->getType(), *Low));
+      return new ICmpInst(Pred == ICmpInst::ICMP_EQ ? ICmpInst::ICMP_ULT
+                                                     : ICmpInst::ICMP_UGE,
+                          Sub, ConstantInt::get(X->getType(), Diff));
+    }
+  }
+
+  }
+  */
   if (auto *Res = foldICmpEqualityWithOffset(
           I, Builder, getSimplifyQuery().getWithInstruction(&I)))
     return Res;

   return nullptr;
+  return nullptr;
 }

